type Claims interface {
	// Valid reports whether the claims are internally consistent. It is called
	// during parsing; returning a non-nil error rejects the token. The
	// registered-claim time checks are performed separately by the parser's
	// validator, so lightweight implementations may simply return nil.
	Valid() error
}

type Clock interface {
	Now() time.Time
}

type HTTPDoer interface {
	Do(req *http.Request) (*http.Response, error)
}

type JSONWebKey struct {
	// Key holds the parsed Go crypto key (see the type list above). It is
	// populated by ParseJWK and by JSONWebKeySet parsing; it is nil on a JWK
	// that was only unmarshaled as JSON.
	Key any `json:"-"`

	// Kty is the key type: "RSA", "EC", "OKP", or "oct".
	Kty string `json:"kty"`
	// Use is the intended public key use, "sig" or "enc" (optional).
	Use string `json:"use,omitempty"`
	// KeyOps lists the permitted key operations (optional).
	KeyOps []string `json:"key_ops,omitempty"`
	// Alg is the algorithm intended for use with the key, e.g. "RS256".
	Alg string `json:"alg,omitempty"`
	// Kid is the key ID used to match a JWK against a token's "kid" header.
	Kid string `json:"kid,omitempty"`

	// RSA public parameters.
	N string `json:"n,omitempty"` // modulus
	E string `json:"e,omitempty"` // public exponent
	// RSA private parameters.
	D  string `json:"d,omitempty"`  // private exponent (also EC/OKP private key)
	P  string `json:"p,omitempty"`  // first prime factor
	Q  string `json:"q,omitempty"`  // second prime factor
	Dp string `json:"dp,omitempty"` // d mod (p-1)
	Dq string `json:"dq,omitempty"` // d mod (q-1)
	Qi string `json:"qi,omitempty"` // q^-1 mod p

	// EC / OKP parameters.
	Crv string `json:"crv,omitempty"` // curve, e.g. "P-256" or "Ed25519"
	X   string `json:"x,omitempty"`   // x coordinate (EC) or public key (OKP)
	Y   string `json:"y,omitempty"`   // y coordinate (EC)

	// oct parameter.
	K string `json:"k,omitempty"` // symmetric key material
}

type JSONWebKeySet struct {
	Keys []JSONWebKey `json:"keys"`
}

type JWKSCache struct {
	// contains filtered or unexported fields
}

type NumericDate struct {
	time.Time
}

type Parser struct {
	// contains filtered or unexported fields
}

type SigningMethod interface {
	// Alg returns the JWS "alg" header value, e.g. "HS256" or "ES384".
	Alg() string

	// Sign signs signingString (the base64url header + "." + base64url
	// payload) with key and returns the raw signature bytes. The key type
	// depends on the method (e.g. []byte for HMAC, *rsa.PrivateKey for RSA).
	Sign(signingString string, key any) ([]byte, error)

	// Verify checks that sig is a valid signature over signingString using
	// key. It returns nil on success and a non-nil error (wrapping
	// ErrSignatureInvalid) on failure.
	Verify(signingString string, sig []byte, key any) error
}

type SigningMethodECDSA struct {
	Name string
	Hash crypto.Hash
	// KeySize is the byte length of each of r and s for this curve.
	KeySize int
}

type SigningMethodHMAC struct {
	Name string
	Hash crypto.Hash
}

type SigningMethodRSA struct {
	Name string
	Hash crypto.Hash
}

type SigningMethodRSAPSS struct {
	Name    string
	Hash    crypto.Hash
	Options *rsa.PSSOptions
}

type Token struct {
	// Raw is the original compact serialization, populated by the parser.
	Raw string
	// Method is the signing method selected from the alg header (or supplied to
	// New).
	Method SigningMethod
	// Header is the decoded JOSE header.
	Header map[string]any
	// Claims is the token payload.
	Claims Claims
	// Signature is the decoded (raw) signature, populated by the parser.
	Signature []byte
	// Valid reports whether the parser considered the token valid.
	Valid bool
}

type Validator struct {
	// contains filtered or unexported fields
}

